    35→// Extract the value of the key from the cookie header.
    36→absl::optional<std::string> CookieValueSelector::extract(Http::HeaderMap& map) const {
    37→  std::string value = Envoy::Http::Utility::parseCookieValue(map, cookie_);
    38→  if (!value.empty()) {
    39→    return {std::move(value)};
    40→  }
    41→  return absl::nullopt;
    42→}
    43→
    44→Rule::Rule(const ProtoRule& rule, Regex::Engine& regex_engine) : rule_(rule) {
    45→  // Ensure only one of header and cookie is specified.
    46→  // TODO(radha13): remove this once we are on v4 and these fields are folded into a oneof.
    47→  if (!rule.cookie().empty() && !rule.header().empty()) {
    48→    throw EnvoyException("Cannot specify both header and cookie");
    49→  }
    50→
    51→  // Initialize the shared pointer.
    52→  if (!rule.header().empty()) {
    53→    selector_ =
    54→        std::make_shared<HeaderValueSelector>(Http::LowerCaseString(rule.header()), rule.remove());
    55→  } else if (!rule.cookie().empty()) {
    56→    selector_ = std::make_shared<CookieValueSelector>(rule.cookie());
    57→  } else {
    58→    throw EnvoyException("One of Cookie or Header option needs to be specified");
    59→  }
    60→
    61→  // Rule must have at least one of the `on_header_*` fields set.
    62→  if (!rule.has_on_header_present() && !rule.has_on_header_missing()) {
    63→    const auto& error = fmt::format("header to metadata filter: rule for {} has neither "
    64→                                    "`on_header_present` nor `on_header_missing` set",
    65→                                    selector_->toString());
    66→    throw EnvoyException(error);
    67→  }
    68→
    69→  // Ensure value and regex_value_rewrite are not mixed.
    70→  // TODO(rgs1): remove this once we are on v4 and these fields are folded into a oneof.
    71→  if (!rule.on_header_present().value().empty() &&
    72→      rule.on_header_present().has_regex_value_rewrite()) {
    73→    throw EnvoyException("Cannot specify both value and regex_value_rewrite");
    74→  }
    75→
    76→  // Remove field is un-supported for cookie.
    77→  if (!rule.cookie().empty() && rule.remove()) {
    78→    throw EnvoyException("Cannot specify remove for cookie");
    79→  }
    80→
    81→  if (rule.has_on_header_missing() && rule.on_header_missing().value().empty()) {
    82→    throw EnvoyException("Cannot specify on_header_missing rule with an empty value");
    83→  }
    84→
    85→  if (rule.on_header_present().has_regex_value_rewrite()) {
    86→    const auto& rewrite_spec = rule.on_header_present().regex_value_rewrite();
    87→    regex_rewrite_ =
    88→        THROW_OR_RETURN_VALUE(Regex::Utility::parseRegex(rewrite_spec.pattern(), regex_engine),
    89→                              Regex::CompiledMatcherPtr);
    90→    regex_rewrite_substitution_ = rewrite_spec.substitution();
    91→  }
    92→}
    93→
    94→Config::Config(const envoy::extensions::filters::http::header_to_metadata::v3::Config config,
    95→               Regex::Engine& regex_engine, const bool per_route) {
    96→  request_set_ = Config::configToVector(config.request_rules(), request_rules_, regex_engine);
    97→  response_set_ = Config::configToVector(config.response_rules(), response_rules_, regex_engine);
    98→
    99→  // Note: empty configs are fine for the global config, which would be the case for enabling
   100→  //       the filter globally without rules and then applying them at the virtual host or
   101→  //       route level. At the virtual or route level, it makes no sense to have an empty
   102→  //       config so we throw an error.
   103→  if (per_route && !response_set_ && !request_set_) {
   104→    throw EnvoyException("header_to_metadata_filter: Per filter configs must at least specify "
   105→                         "either request or response rules");
   106→  }
   107→}
   108→
   109→bool Config::configToVector(const ProtobufRepeatedRule& proto_rules, HeaderToMetadataRules& vector,
   110→                            Regex::Engine& regex_engine) {
   111→  if (proto_rules.empty()) {
   112→    ENVOY_LOG(debug, "no rules provided");
   113→    return false;
   114→  }
   115→
   116→  for (const auto& entry : proto_rules) {
   117→    vector.emplace_back(entry, regex_engine);
   118→  }
   119→
   120→  return true;
   121→}
   122→
   123→HeaderToMetadataFilter::HeaderToMetadataFilter(const ConfigSharedPtr config) : config_(config) {}
   124→
   125→HeaderToMetadataFilter::~HeaderToMetadataFilter() = default;
   126→
   127→Http::FilterHeadersStatus HeaderToMetadataFilter::decodeHeaders(Http::RequestHeaderMap& headers,
   128→                                                                bool) {
   129→  const auto* config = getConfig();
   130→  if (config->doRequest()) {
   131→    writeHeaderToMetadata(headers, config->requestRules(), *decoder_callbacks_);
   132→  }
   133→
   134→  return Http::FilterHeadersStatus::Continue;
   135→}
   136→
   137→void HeaderToMetadataFilter::setDecoderFilterCallbacks(
   138→    Http::StreamDecoderFilterCallbacks& callbacks) {
   139→  decoder_callbacks_ = &callbacks;
   140→}
   141→
   142→Http::FilterHeadersStatus HeaderToMetadataFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
   143→                                                                bool) {
   144→  const auto* config = getConfig();
   145→  if (config->doResponse()) {
   146→    writeHeaderToMetadata(headers, config->responseRules(), *encoder_callbacks_);
   147→  }
   148→  return Http::FilterHeadersStatus::Continue;
   149→}
   150→
   151→void HeaderToMetadataFilter::setEncoderFilterCallbacks(
   152→    Http::StreamEncoderFilterCallbacks& callbacks) {
   153→  encoder_callbacks_ = &callbacks;
   154→}
   155→
   156→bool HeaderToMetadataFilter::addMetadata(StructMap& struct_map, const std::string& meta_namespace,
   157→                                         const std::string& key, std::string value, ValueType type,
   158→                                         ValueEncode encode) const {
   159→  ProtobufWkt::Value val;
   160→
   161→  ASSERT(!value.empty());
   162→
   163→  if (value.size() >= MAX_HEADER_VALUE_LEN) {
   164→    // Too long, go away.
   165→    ENVOY_LOG(debug, "metadata value is too long");
   166→    return false;
   167→  }
   168→
   169→  if (encode == envoy::extensions::filters::http::header_to_metadata::v3::Config::BASE64) {
   170→    value = Base64::decodeWithoutPadding(value);
   171→    if (value.empty()) {
   172→      ENVOY_LOG(debug, "Base64 decode failed");
   173→      return false;
   174→    }
   175→  }
   176→
   177→  // Sane enough, add the key/value.
   178→  switch (type) {
   179→    PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
   180→  case envoy::extensions::filters::http::header_to_metadata::v3::Config::STRING:
   181→    val.set_string_value(std::move(value));
   182→    break;
   183→  case envoy::extensions::filters::http::header_to_metadata::v3::Config::NUMBER: {
   184→    double dval;
   185→    if (absl::SimpleAtod(StringUtil::trim(value), &dval)) {
   186→      val.set_number_value(dval);
   187→    } else {
   188→      ENVOY_LOG(debug, "value to number conversion failed");
   189→      return false;
   190→    }
   191→    break;
   192→  }
   193→  case envoy::extensions::filters::http::header_to_metadata::v3::Config::PROTOBUF_VALUE: {
   194→    if (!val.ParseFromString(value)) {
   195→      ENVOY_LOG(debug, "parse from decoded string failed");
   196→      return false;
   197→    }
   198→    break;
   199→  }
   200→  }
   201→
   202→  auto& keyval = struct_map[meta_namespace];
   203→  (*keyval.mutable_fields())[key] = std::move(val);
   204→
   205→  return true;
   206→}
   207→
   208→const std::string& HeaderToMetadataFilter::decideNamespace(const std::string& nspace) const {
   209→  return nspace.empty() ? HttpFilterNames::get().HeaderToMetadata : nspace;
   210→}
   211→
   212→// add metadata['key']= value depending on header present or missing case
   213→void HeaderToMetadataFilter::applyKeyValue(std::string&& value, const Rule& rule,
   214→                                           const KeyValuePair& keyval, StructMap& np) {
   215→  if (!keyval.value().empty()) {
   216→    value = keyval.value();
   217→  } else {
   218→    const auto& matcher = rule.regexRewrite();
   219→    if (matcher != nullptr) {
   220→      value = matcher->replaceAll(value, rule.regexSubstitution());
   221→    }
   222→  }
   223→  if (!value.empty()) {
   224→    const auto& nspace = decideNamespace(keyval.metadata_namespace());
   225→    addMetadata(np, nspace, keyval.key(), value, keyval.type(), keyval.encode());
   226→  } else {
   227→    ENVOY_LOG(debug, "value is empty, not adding metadata");
   228→  }
   229→}
   230→
   231→void HeaderToMetadataFilter::writeHeaderToMetadata(Http::HeaderMap& headers,
   232→                                                   const HeaderToMetadataRules& rules,
   233→                                                   Http::StreamFilterCallbacks& callbacks) {
   234→  StructMap structs_by_namespace;
   235→
   236→  for (const auto& rule : rules) {
   237→    const auto& proto_rule = rule.rule();
   238→    absl::optional<std::string> value = rule.selector_->extract(headers);
   239→
   240→    if (value && proto_rule.has_on_header_present()) {
   241→      applyKeyValue(std::move(value).value_or(""), rule, proto_rule.on_header_present(),
   242→                    structs_by_namespace);
   243→    } else if (!value && proto_rule.has_on_header_missing()) {
   244→      applyKeyValue(std::move(value).value_or(""), rule, proto_rule.on_header_missing(),
   245→                    structs_by_namespace);
   246→    }
   247→  }
   248→  // Any matching rules?
   249→  if (!structs_by_namespace.empty()) {
   250→    for (auto const& entry : structs_by_namespace) {
   251→      callbacks.streamInfo().setDynamicMetadata(entry.first, entry.second);
   252→    }
   253→  }
   254→}
   255→
   256→// TODO(rgs1): this belongs in one of the filter interfaces, see issue #10164.
   257→const Config* HeaderToMetadataFilter::getConfig() const {
   258→  // Cached config pointer.
   259→  if (effective_config_) {
   260→    return effective_config_;
   261→  }
   262→
   263→  effective_config_ = Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
   264→  if (effective_config_) {
   265→    return effective_config_;
   266→  }
   267→
   268→  effective_config_ = config_.get();
   269→  return effective_config_;
   270→}
   271→
   272→} // namespace HeaderToMetadataFilter
   273→} // namespace HttpFilters
   274→} // namespace Extensions
   275→} // namespace Envoy
