  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(req_info_));
  auto req_status = filter_->decodeHeaders(request_headers, false);
  EXPECT_EQ(req_status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(request_headers.get("x-custom-header"), "custom-value");

  // Test response headers
  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_CALL(encoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(req_info_));
  auto resp_status = filter_->encodeHeaders(response_headers, false);
  EXPECT_EQ(resp_status, Http::FilterHeadersStatus::Continue);
  EXPECT_EQ(response_headers.get("x-response-header"), "response-value");
}

/**
 * Test empty configuration.
 */
TEST_F(CustomHeaderInjectionTest, EmptyConfig) {
  const std::string empty_config = "{}";
  initializeFilter(empty_config);

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_CALL(decoder_callbacks_, streamInfo()).WillRepeatedly(testing::ReturnRef(req_info_));
  auto status = filter_->decodeHeaders(request_headers, false);

  EXPECT_EQ(status, Http::FilterHeadersStatus::Continue);
}

} // namespace
} // namespace CustomHeaderInjectionFilter
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

