    12→Config::Config(const ProtoConfig& config, const bool per_route) {
    13→  // Copy request headers from config
    14→  for (const auto& header : config.request_headers()) {
    15→    request_headers_.push_back(header);
    16→  }
    17→
    18→  // Copy response headers from config
    19→  for (const auto& header : config.response_headers()) {
    20→    response_headers_.push_back(header);
    21→  }
    22→
    23→  // For per-route config, ensure at least one header injection rule is specified
    24→  if (per_route && request_headers_.empty() && response_headers_.empty()) {
